// ElevenLabs Conversation Initiation Webhook (HORECA)
// Riceve: { caller_id, agent_id, called_number, call_sid }
const b = $json.body || $json;
const caller = (b.caller_id || '').trim();

// >>> QUI in produzione: un nodo Postgres PRIMA di questo che cerca il contatto
// per numero e ne passa i campi. Per ora c=null simula un chiamante sconosciuto.
let c = null;
// Esempio: c = { nome:'Gino', cognome:'Rossi', societa:'Trattoria da Gino',
//               stato:'cliente', ruolo:'Titolare', email:'gino@x.it',
//               ultimo:'#1 del 08/06, 3 articoli, 525 EUR', riassunto:'...' };

let dv, saluto;
if (c) {
  saluto = 'Buongiorno signor ' + (c.cognome || c.nome) + ', come posso aiutarla?';
  dv = {
    cliente_conosciuto: 'si',
    nome_cliente: ((c.nome||'') + ' ' + (c.cognome||'')).trim(),
    nome: c.nome || '',
    societa: c.societa || '',
    stato_cliente: c.stato || '',
    ruolo: c.ruolo || '',
    email_cliente: c.email || '',
    ultimo_ordine: c.ultimo || 'nessuno',
    riassunto_cliente: c.riassunto || '',
    saluto: saluto
  };
} else {
  saluto = 'Buongiorno, come posso aiutarla?';
  dv = {
    cliente_conosciuto: 'no',
    nome_cliente: '', nome: '', societa: '', stato_cliente: '', ruolo: '',
    email_cliente: '', ultimo_ordine: 'nessuno',
    riassunto_cliente: 'Chiamante non riconosciuto: nuovo contatto da registrare.',
    saluto: saluto
  };
}
dv.telefono_chiamante = caller;

return [{ json: {
  type: 'conversation_initiation_client_data',
  dynamic_variables: dv
} }];

// ElevenLabs Post-Call Webhook (HORECA): trascrizione + riassunto
const b = $json.body || $json;
if (b.type !== 'post_call_transcription') {
  return [{ json: { ok: true, ignored: b.type } }];
}
const data = b.data || {};
const turns = data.transcript || [];
const nl = String.fromCharCode(10);
const trascrizione = turns
  .map(function (t) { return (t.role === 'user' ? 'Cliente: ' : 'Assistente: ') + (t.message || ''); })
  .join(nl);
const an = data.analysis || {};
const meta = data.metadata || {};
const dv = ((data.conversation_initiation_client_data || {}).dynamic_variables) || {};
const telefono = dv.telefono_chiamante || '';

// >>> QUI in produzione: un nodo Postgres INSERT per salvare la chiamata
// (telefono, trascrizione, riassunto, durata) sul contatto.

return [{ json: {
  ok: true,
  telefono: telefono,
  durata_sec: meta.call_duration_secs || null,
  riassunto: an.transcript_summary || '',
  trascrizione: trascrizione
} }];
